// 1. Get the raw text output from the previous Gemini node
const rawText = $input.item.json.candidates[0].content.parts[0].text;

// --- Helper Function: Extract text between two headers (Flexible) ---
function extractSection(text, startHeader, endHeader) {
  // Escape special regex characters in the header string
  const escapedHeader = startHeader.replace(/[.*+?^${}()|[\]\\]/g, '\\$&').replace(/\s+/g, '\\s+');

  // Start Pattern: Matches optional numbering, bolding, and the header itself
  const startPattern = `(?:^|\\n)(?:[\\d\\.\\)\\-\\s]*)?(?:\\*\\*|__)?${escapedHeader}(?:.*?)?(?:\\*\\*|__)?[:\\s]*`;

  const startRegex = new RegExp(startPattern, 'i');
  const startMatch = text.match(startRegex);

  if (!startMatch) return null;

  const startIndex = startMatch.index + startMatch[0].length;

  // Find End Index
  let endIndex = text.length;
  if (endHeader) {
    const endHeaders = Array.isArray(endHeader) ? endHeader : [endHeader];
    const combinedEndPattern = endHeaders.map(h => {
      const esc = h.replace(/[.*+?^${}()|[\]\\]/g, '\\$&').replace(/\s+/g, '\\s+');
      return `(?:^|\\n)(?:[\\d\\.\\)\\-\\s]*)?(?:\\*\\*|__)?${esc}`;
    }).join('|');

    const endRegex = new RegExp(combinedEndPattern, 'i');
    const remainingText = text.substring(startIndex);
    const endMatch = remainingText.match(endRegex);

    if (endMatch) {
      endIndex = startIndex + endMatch.index;
    }
  }

  // Cleanup leading/trailing junk
  return text.substring(startIndex, endIndex).trim();
}

// --- Helper Function: Extract content inside explicit DELIMITERS ---
function extractDelimitedBlock(text, startDelimiter, endDelimiter) {
  const startIndex = text.indexOf(startDelimiter);
  if (startIndex === -1) return null;

  const contentStart = startIndex + startDelimiter.length;
  const endIndex = text.indexOf(endDelimiter, contentStart);

  if (endIndex === -1) return text.substring(contentStart).trim();

  return text.substring(contentStart, endIndex).trim();
}

// --- Helper Function: Parse Video Configuration ---
function parseConfig(configText) {
  const config = {};
  if (!configText) return config;
  const lines = configText.split('\n');
  lines.forEach(line => {
    const parts = line.split(':');
    if (parts.length >= 2) {
      const key = parts[0].replace(/^[-\u2022\d\)\.\s\*]+/, '').replace(/\*+/g, '').trim(); 
      const value = parts.slice(1).join(':').trim();
      if (key && value) config[key] = value;
    }
  });
  return config;
}

// --- Helper Function: Robust JSON Parsing (The Fix) ---
function parseJSONBlock(rawString) {
  if (!rawString) return {};
  try {
    // 1. Find the index of the first '{'
    const firstBrace = rawString.indexOf('{');
    // 2. Find the index of the last '}'
    const lastBrace = rawString.lastIndexOf('}');

    // 3. If valid braces found, extract ONLY that substring
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      const jsonCandidate = rawString.substring(firstBrace, lastBrace + 1);
      return JSON.parse(jsonCandidate);
    }

    // Fallback: simple cleanup if braces methodology fails
    let cleanString = rawString.replace(/```json/g, '').replace(/```/g, '');
    return JSON.parse(cleanString);
  } catch (e) {
    return { error: "Failed to parse JSON", raw_text: rawString };
  }
}

// --- MAIN EXTRACTION LOGIC ---

const rawConfig = extractSection(rawText, "VIDEO CONFIGURATION", "RESEARCH SUMMARY");
const videoConfig = parseConfig(rawConfig);

const researchSummary = extractSection(rawText, "RESEARCH SUMMARY", "PERSONA JSON");

const rawPersona = extractSection(rawText, "PERSONA JSON", "PRODUCT PROFILE JSON");
const personaObj = parseJSONBlock(rawPersona);

const rawProduct = extractSection(rawText, "PRODUCT PROFILE JSON", "PROMPT FOR FRAME 0");
const productObj = parseJSONBlock(rawProduct);

const frame0Prompt = extractSection(rawText, "PROMPT FOR FRAME 0", ["===SORA_PROMPT_START==="]);

const soraVideoPrompt = extractDelimitedBlock(rawText, "===SORA_PROMPT_START===", "===SORA_PROMPT_END===");

const strategySnapshot = extractSection(rawText, "VIDEO STRATEGY SNAPSHOT", null); 


// --- RETURN STRUCTURED DATA ---
return {
  json: {
    vid_config: videoConfig,
    research_summary: researchSummary,
    persona: personaObj.persona || personaObj, 
    product_profile: productObj.product_profile || productObj,
    start_frame_image_prompt: frame0Prompt,
    vidgen_prompt: soraVideoPrompt,
    strategy_snapshot: strategySnapshot
  }
};

